    /** Lookup by series slug (e.g. "wta", "nfl"). */
    slug?: string;
    /** Keyword search across series title / description. */
    query?: string;
    /** Filter by recurrence cadence ('daily', 'weekly', 'annual', ...). */
    recurrence?: string;
    /** Maximum number of results to return. */
